def make_example(user_msg, assistant_msg):
    return {
        "messages": [
            {"role": "system", "content": SYSTEM_PROMPT},
            {"role": "user", "content": user_msg},
            {"role": "assistant", "content": assistant_msg},
        ]
    }


def generate_multi_turn(all_single, n=200):
    """Genera conversaciones multi-turn combinando pares."""
    random.seed(42)
    multi = []

    followups_user = [
        "طيب وبعدين شو أسوي؟",
        "شكراً يا حبيبي على النصيحة",
        "تمام بنسوي جذي إن شاء الله",
        "ما شاء الله عليك دايماً عندك الحل",
        "أوكي بس عندي سؤال ثاني",
        "جزاك الله خير على المساعدة",
        "إن شاء الله بنجرب هالشي",
        "حلو حلو، شكراً لك",
        "الله يبارك فيك يا الغالي",
        "طيب وإذا ما نفع شو أسوي؟",
    ]

    followups_assistant = [
        "العفو يا غالي! هذا واجبنا مع بعض. العايلة دايماً تساعد بعضها. إذا تبي أي شي ثاني لا تتردد.",
        "إن شاء الله يا رب. الله يوفقكم ويسهل عليكم. نحن عايلة وحدة ودايماً مع بعض.",
        "الحمد لله، التجارب علمتنا وايد. أهم شي إن العايلة تكون مع بعض في السراء والضراء.",
        "ابشر يا الغالي! أي شي تحتاجه قولي. ما عندنا أسرار ولا تكلف مع العايلة.",
        "الله يبارك فيك. وإذا احتجت شي ثاني أنا موجود. المهم تطبق اللي قلت لك عليه وتشوف النتيجة.",
        "بالتوفيق إن شاء الله! وتذكر إن الصبر مفتاح كل شي. وإذا واجهتك مشكلة رجعلي.",
        "إن شاء الله كل شي بيكون تمام. المهم ما تستعجل وخذ الأمور خطوة خطوة. وادعي ربك يسهل.",
        "جرب وشوف، وإذا ما نفع بنلقى طريقة ثانية. المهم ما نستسلم. العايلة سندك دايماً.",
        "على راسي يا حبيبي! كل ما تحتاج شي أنا هني. هذا دورنا مع بعض والله.",
        "الله يعينكم ويسهل عليكم. وإذا الأمور ما تحسنت جربوا الخطوة اللي بعدها. ما فيه مشكلة ما لها حل إن شاء الله.",
    ]

    all_categories = [GREETINGS, FOOD, CHILDREN, HEALTH, CELEBRATIONS,
                      RELIGION, RELATIONSHIPS, DAILY_LIFE, MODERN, TRADITIONS, TRAVEL, PROBLEMS]

    for _ in range(n):
        # Pick a greeting + topic, or two topics
        if random.random() < 0.3:
            # Greeting + topic
            g_u, g_a = random.choice(GREETINGS)
            cat = random.choice(all_categories)
            t_u, t_a = random.choice(cat)
            multi.append({
                "messages": [
                    {"role": "system", "content": SYSTEM_PROMPT},
                    {"role": "user", "content": g_u},
                    {"role": "assistant", "content": g_a},
                    {"role": "user", "content": t_u},
                    {"role": "assistant", "content": t_a},
                ]
            })
        else:
            # Topic + followup
            cat = random.choice(all_categories)
            t_u, t_a = random.choice(cat)
            f_u = random.choice(followups_user)
            f_a = random.choice(followups_assistant)
            multi.append({
                "messages": [
                    {"role": "system", "content": SYSTEM_PROMPT},
                    {"role": "user", "content": t_u},
                    {"role": "assistant", "content": t_a},
                    {"role": "user", "content": f_u},
                    {"role": "assistant", "content": f_a},
                ]
            })

    return multi


def generate_three_turn(n=100):
    """Genera conversaciones de 3 turns."""
    random.seed(123)
    three_turn = []

    all_categories = [FOOD, CHILDREN, HEALTH, CELEBRATIONS, DAILY_LIFE, MODERN, RELATIONSHIPS, TRAVEL, PROBLEMS]

    mid_questions = [
        "وبعدين شو أسوي؟",
        "طيب وإذا ما نفع؟",
        "أحسنت، عندي سؤال ثاني بعد",
        "تمام، بس فيه شي ثاني أبي أسأل عنه",
    ]

    mid_answers = [
        "أكيد سأل! أنا هني عشان أساعدك في أي شي.",
        "تفضل يا الغالي، شو السؤال؟",
        "بالتأكيد، قولي شو تبي.",
        "هيه تفضل، شو عندك؟",
    ]

    for _ in range(n):
        cat1 = random.choice(all_categories)
        cat2 = random.choice(all_categories)
        t1_u, t1_a = random.choice(cat1)
        mid_q = random.choice(mid_questions)
        mid_a = random.choice(mid_answers)
        t2_u, t2_a = random.choice(cat2)

        three_turn.append({
            "messages": [
                {"role": "system", "content": SYSTEM_PROMPT},
                {"role": "user", "content": t1_u},
                {"role": "assistant", "content": t1_a},
                {"role": "user", "content": mid_q},
                {"role": "assistant", "content": mid_a},
                {"role": "user", "content": t2_u},
                {"role": "assistant", "content": t2_a},
            ]
        })

    return three_turn


def main():
    output_path = Path("data/raw/conversations_1500.jsonl")

    all_examples = []

    # Single-turn from all categories
    for category in [GREETINGS, FOOD, CHILDREN, HEALTH, CELEBRATIONS,
                     RELIGION, RELATIONSHIPS, DAILY_LIFE, MODERN,
                     TRADITIONS, TRAVEL, PROBLEMS, REFUSALS]:
        for user_msg, assistant_msg in category:
            all_examples.append(make_example(user_msg, assistant_msg))

    single_count = len(all_examples)
    print(f"Single-turn: {single_count}")

    # Multi-turn (2 turns)
    multi = generate_multi_turn(all_examples, n=700)
    all_examples.extend(multi)
    print(f"Multi-turn (2): {len(multi)}")

    # Three-turn
    three = generate_three_turn(n=300)
    all_examples.extend(three)
    print(f"Three-turn: {len(three)}")

    # Shuffle
    random.seed(42)
    random.shuffle(all_examples)

    # Write
    output_path.parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, "w", encoding="utf-8") as f:
        for ex in all_examples:
            f.write(json.dumps(ex, ensure_ascii=False) + "\n")

    print(f"\nTotal: {len(all_examples)} ejemplos en {output_path}")


if __name__ == "__main__":
    main()
